    periodo character varying(40),
    anio smallint,
    mes smallint,
    quincena smallint,
    dias smallint DEFAULT 0 NOT NULL,
    horas smallint DEFAULT 0 NOT NULL,
    minutos smallint DEFAULT 0 NOT NULL,
    motivo text,
    observaciones text,
    justificacion text,
    folio_justificacion character varying(60),
    capturado_por_user_id integer,
    fuente character varying(100),
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT inc_dias_chk CHECK (((dias >= 0) AND (dias <= 366))),
    CONSTRAINT inc_fechas_chk CHECK (((fecha_fin IS NULL) OR (fecha_inicio IS NULL) OR (fecha_fin >= fecha_inicio))),
    CONSTRAINT inc_horas_chk CHECK (((horas >= 0) AND (horas <= 23))),
    CONSTRAINT inc_mes_chk CHECK (((mes IS NULL) OR ((mes >= 1) AND (mes <= 12)))),
    CONSTRAINT inc_minutos_chk CHECK (((minutos >= 0) AND (minutos <= 59))),
    CONSTRAINT inc_quincena_chk CHECK (((quincena IS NULL) OR ((quincena >= 1) AND (quincena <= 2))))
);


