--
-- Name: v_dashboard_resumen; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_dashboard_resumen AS
 SELECT count(*) AS total_oficios,
    count(*) FILTER (WHERE ((e.nombre)::text = 'Recibido'::text)) AS recibidos,
    count(*) FILTER (WHERE ((e.nombre)::text = 'En Proceso'::text)) AS en_proceso,
    count(*) FILTER (WHERE ((e.nombre)::text = 'En Revisión'::text)) AS en_revision,
    count(*) FILTER (WHERE ((e.nombre)::text = 'Contestado'::text)) AS contestados,
    count(*) FILTER (WHERE ((e.nombre)::text = 'Archivado'::text)) AS archivados
   FROM (public.oficios o
     JOIN public.estados_oficio e ON ((e.id = o.estado_id)));


--
-- Name: v_oficios_completo; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_oficios_completo AS
 SELECT o.id,
    o.folio_tesoreria,
    o.numero_folio,
    o.anio_folio,
    o.folio_minutario,
    o.folio_direccion,
    o.folio_interno_texto,
    o.asunto,
    o.descripcion,
    o.observaciones,
    o.fecha_recepcion,
    o.fecha_oficio_tics,
    o.fecha_acuse,
    o.fecha_compromiso,
    o.fecha_resolucion,
    o.realizo,
    o.created_at,
    o.updated_at,
    o.tipo_oficio_id,
    t.clave AS tipo_oficio_clave,
    t.nombre AS tipo_oficio_nombre,
    o.dependencia_id,
    d.nombre AS dependencia_nombre,
    d.clave AS dependencia_clave,
    o.area_interna_id,
    ai.nombre AS area_interna_nombre,
    ai.clave AS area_interna_clave,
    o.estado_id,
    e.nombre AS estado_nombre,
    e.color AS estado_color,
    uc.nombre AS capturo_nombre,
    ur.nombre AS responsable_nombre,
        CASE
            WHEN (((t.clave)::text = 'INTERNO'::text) AND ((COALESCE(o.folio_interno_texto, ''::character varying))::text <> ''::text)) THEN o.folio_interno_texto
            WHEN (((t.clave)::text = 'INTERNO'::text) AND ((COALESCE(o.folio_direccion, ''::character varying))::text <> ''::text)) THEN o.folio_direccion
            WHEN (((t.clave)::text = 'CONOCIMIENTO'::text) AND ((COALESCE(o.folio_direccion, ''::character varying))::text <> ''::text)) THEN o.folio_direccion
            WHEN ((t.clave)::text = 'CONOCIMIENTO'::text) THEN (((('CON/'::text || (o.numero_folio)::text) || '/'::text) || (o.anio_folio)::text))::character varying
            ELSE o.folio_tesoreria
        END AS folio_display,
    ( SELECT count(*) AS count
           FROM public.movimientos_oficio m
          WHERE (m.oficio_id = o.id)) AS total_movimientos,
    ( SELECT count(*) AS count
           FROM public.evidencias_pdf ep
          WHERE (ep.oficio_id = o.id)) AS total_evidencias
   FROM ((((((public.oficios o
     LEFT JOIN public.tipos_oficio t ON ((t.id = o.tipo_oficio_id)))
     LEFT JOIN public.dependencias d ON ((d.id = o.dependencia_id)))
     LEFT JOIN public.areas_internas ai ON ((ai.id = o.area_interna_id)))
     LEFT JOIN public.estados_oficio e ON ((e.id = o.estado_id)))
     LEFT JOIN public.usuarios uc ON ((uc.id = o.usuario_capturo_id)))
     LEFT JOIN public.usuarios ur ON ((ur.id = o.usuario_responsable_id)));


--
-- Name: vacaciones; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.vacaciones (
    id integer NOT NULL,
    personal_id integer NOT NULL,
    periodo character varying(40),
    anio smallint,
    periodo_texto text,
    fecha_solicitud date,
    fecha_inicio date NOT NULL,
    fecha_fin date NOT NULL,
    fecha_regreso date,
    fecha_recibido_coord date,
    dias_solicitados smallint DEFAULT 0 NOT NULL,
    dias_disfrutados smallint DEFAULT 0 NOT NULL,
    dias_pendientes smallint DEFAULT 0 NOT NULL,
    folio_tm character varying(60),
    estatus_id integer NOT NULL,
    capturado_por_user_id integer,
    observaciones text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT vac_dias_dis_chk CHECK ((dias_disfrutados >= 0)),
    CONSTRAINT vac_dias_pen_chk CHECK ((dias_pendientes >= 0)),
    CONSTRAINT vac_dias_sol_chk CHECK ((dias_solicitados >= 0)),
    CONSTRAINT vac_fechas_chk CHECK ((fecha_fin >= fecha_inicio)),
    CONSTRAINT vac_regreso_chk CHECK (((fecha_regreso IS NULL) OR (fecha_regreso >= fecha_fin)))
);


